import React, { useState, useEffect, useRef } from 'react';

function DanhSachSanPham() {
  const [sanPham, setSanPham] = useState([]);
  const [trangHienTai, setTrangHienTai] = useState(1);
  const [soLuongSanPhamTrang, setSoLuongSanPhamTrang] = useState(10);
  const containerRef = useRef(null);

  useEffect(() => {
    const layDanhSachSanPham = async () => {
      const response = await fetch(`https://api.example.com/san-pham?page=${trangHienTai}&limit=${soLuongSanPhamTrang}`);
      const data = await response.json();
      setSanPham(data.sanPham);
    };
    layDanhSachSanPham();
  }, [trangHienTai, soLuongSanPhamTrang]);

  const layDanhSachSanPhamTheoTrang = async (trang) => {
    setTrangHienTai(trang);
  };

  const handleScroll = () => {
    const container = containerRef.current;
    if (container.scrollTop + container.offsetHeight >= container.scrollHeight) {
      layDanhSachSanPhamTheoTrang(trangHienTai + 1);
    }
  };

  return (
    <div ref={containerRef} onScroll={handleScroll}>
      <h1>Danh sách sản phẩm</h1>
      <ul>
        {sanPham.map((sanPham, index) => (
          <li key={index}>{sanPham.tenSanPham}</li>
        ))}
      </ul>
      <button onClick={() => layDanhSachSanPhamTheoTrang(trangHienTai - 1)}>Trang trước</button>
      <button onClick={() => layDanhSachSanPhamTheoTrang(trangHienTai + 1)}>Trang sau</button>
    </div>
  );
}

export default DanhSachSanPham;
```

